  ('dietitian-moex-01163', 'dietitian', 'dietitian-moex-110-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '關於驗收工作之敘述，下列何者正確？', '["整包、整袋之食物驗收時，若包數或袋數正確則可收貨", "冷凍食品之驗收，可以冷凍狀態外觀判斷其食材品質", "驗收不合格之貨品可請廠商於期限內取回換新", "雙次抽樣是指一品項同時抽兩個樣品判斷是否合格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "a2d5ceca56de", "answer_pdf_sha1": "0225c1397c30", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
